var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"도착했어, 여기가 전시관이야.","JPN":"着いたよ、ミナ。ここが展示会場だって。","ENG":"We're here. This is the gallery.","TWN":"到了，這裡就是展覽館。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응? 전시관에 벌써부터 사람들이 모여있는데? 무슨 일이지?","JPN":"あれ、会場の前に人だかりが出来てる。なにかあったのかな？","ENG":"Hmm? It's already packed with people. Is something going on?","TWN":"嗯？怎麼已經有人聚集在展覽館裡？是發生什麼事？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"아무리 그래도 그렇지! 이건 너무하잖아!?","JPN":"いくら何でもこれはひどすぎる！！","ENG":"Hey, you can't be serious! You crossed a line here!","TWN":"怎麼可以這樣！會不會太過分！？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ART_NPC_GEASS_NULL","text":{"KOREA":"대체 무슨 헛소리를 하는 건데, 진짜!","JPN":"いったい何を言ってるんだ！　まったく！","ENG":"I seriously have no clue what you're talking about!","TWN":"你在胡說什麼？放尊重點！"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저건 사진부랑 미술부잖아?","JPN":"あれは写真部と美術部？","ENG":"Isn’t that the photography club and art club?","TWN":"他們不是攝影部和美術部的人嗎？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"뭔가 문제가 터졌나보네, 서두르자!","JPN":"早速トラブルになってる。急ごう！","ENG":"Looks like something's up. Let's hurry!","TWN":"好像出事了，我們快去看看！"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"지금이라도 사실대로 말해? 너희가 그런 거잖아!?","JPN":"今からでも正直に言えよ。そっちの仕業だろ？","ENG":"Just admit it already! You're the ones who did it!","TWN":"可以請你說實話嗎？明明就是你們做的！"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ART_NPC_GEASS_NULL","text":{"KOREA":"트집 잡는 것도 적당히 좀 하라고! 우리가 왜 너희 사진을 왜 감췄다는 건데?","JPN":"言いがかりも、いい加減にしてくれ。\\n私たちがそっちの写真を隠してどうするんだ。","ENG":"What are you accusing us of, huh? Why would we steal and hide your club's photos?","TWN":"少在那邊含血噴人！我們幹嘛要把你們的照片藏起來？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"잠깐, 둘 다 우선 진정해. 학생회에서 왔어.","JPN":"待って待って、ふたりとも。まずは落ち着いて。\\n私たちは生徒会よ。","ENG":"Whoa, let's calm down a little. We're from the Student Council.","TWN":"等等，大家先冷靜一下，我們是學生會派來的。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"무슨 일이 있었는지 알려줄래?","JPN":"何があったか教えて。","ENG":"Can you tell me what's going on here?","TWN":"可以說明一下發生什麼事嗎？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"그러니까 사진부에서 전시 예정이었던 사진들이 갑자기 모두 사라졌다는 거야?","JPN":"つまり、写真部で展示予定だった写真が全部消えてしまったってこと？","ENG":"So, all of your photos that were going to be displayed suddenly disappeared?","TWN":"所以意思就是攝影部原本要展出的照片突然全都消失不見嗎？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"그래! 분명 이 녀석들 짓이 틀림없어!","JPN":"ああ！　きっとこいつらの仕業に違いない！","ENG":"Yeah! And the culprits are right there!","TWN":"沒錯！一定是他們做的啦！"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ART_NPC_GEASS_NULL","text":{"KOREA":"그러니까 우리가 왜 그런 짓을 하는데?","JPN":"だから、どうして私たちが\\nそんなことをする必要があるって言うんだ！","ENG":"Like I said, why would we do such a thing?","TWN":"我們到底為什麼要那麼做啦？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"그야, 전시관을 독차지하려고 그런 거겠지!","JPN":"そりゃあ、展示会場を独占したいからだろ！","ENG":"So you'd have the gallery all to yourselves!","TWN":"還不就你們想霸佔展覽館！"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ART_NPC_GEASS_NULL","text":{"KOREA":"증거라도 있어? 애초에 너희들 실수로 잃어버린 거 아니야? 그걸 왜 미술부 탓을 하는 건데?","JPN":"証拠はあるのか？\\nそもそも自分たち写真部のミスで紛失したんじゃないのか？　それを美術部のせいにするなんて……","ENG":"You've got proof? Why are you blaming us when it's obviously your fault that you lost them?!","TWN":"你有證據嗎？根本是你們自己搞丟的吧？還想賴到美術部頭上來？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"두 사람 다 그만해.","JPN":"二人とも、ケンカはやめなさい。","ENG":"The two of you, stop it.","TWN":"你們都少說一句！"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"카렌, 우리는 사진부의 요청으로 여기 온 거니까 사진부가 사진 찾는 걸 도와주자.","JPN":"カレン。私たちは写真部の依頼でここに来たんだし、\\n無くなった写真探しに協力しよう。","ENG":"Kallen, we're here at the photography club's request. Let's help them look for their photos.","TWN":"卡蓮，我們是受攝影部之託來的，就幫攝影部找回照片吧？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"그래, 아무래도 사진을 찾지 못하면 싸움을 말릴 수 없을 것 같아.","JPN":"そうね。写真を見つけない限り、このトラブルは収まりそうにないものね。","ENG":"Yeah, I don't think they'll stop fighting unless we find them.","TWN":"嗯嗯，不把照片找回來的話，我看事情是不會結束的。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응. 그리고 전시 준비도 해야 해. 서두르자.","JPN":"うん。展示の準備もあるから、早く見つけないと。急ごう。","ENG":"Right. And we need to hurry because we need time to prepare for the exhibition.","TWN":"嗯，而且還要預備展出，動作要快。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"어때, 미나? 찾았어?","JPN":"どう、ミナ？　見つかった？","ENG":"Any luck, Mina?","TWN":"怎麼樣，米娜？有找到嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니. 사진부가 알려준 사진이 있을 법한 장소는 전부 찾아봤는데 없었어.","JPN":"いや、写真部が教えてくれた\\n写真のありそうな場所は全部探したけど見つからなかった。","ENG":"No. I looked everywhere the photography club members told me to, but no dice.","TWN":"沒有，攝影部說照片可能會在的地方我全都找過了，但都沒看到。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"그러니까 말했잖아. 누군가가 우리 사진을 훔쳐간 거라고.","JPN":"だから言ったじゃないか。誰かが俺たちの写真を盗んだって。","ENG":"I'm telling you. Somebody stole our photos.","TWN":"我不是說了嗎？是有人把我們的照片偷走了！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"자, 알겠지? 이제 시간이 없어. 지금이라도 미술부 녀석들한테 따지러 가자.","JPN":"これでわかっただろう？　もう時間がない。\\n今からでも美術部のやつらを問い詰めて返してもらおう。","ENG":"Now, you understand? We don't have time. Let's go confront the art club about it.","TWN":"沒錯吧？沒時間了，快去找美術部的人問清楚吧！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};